import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";

const { text, usage, finishReason } = await generateText({
  model: openai("gpt-4o"),
  prompt: "Explain the difference between TCP and UDP in two sentences.",
});

console.log(text);
// "TCP provides reliable, ordered delivery with error checking,
//  while UDP is connectionless and prioritises low latency over reliability."

console.log(usage.totalTokens);   // 55
console.log(finishReason);        // "stop"  (or "length", "tool-calls", "content-filter")

import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";

const { text } = await generateText({
  model: openai("gpt-4o"),
  system: "You are a technical writer. Use plain English and avoid jargon.",
  messages: [
    { role: "user",      content: "What is idempotency?" },
    { role: "assistant", content: "An operation is idempotent if..." },
    { role: "user",      content: "Give a REST API example." },
  ],
  temperature: 0.3,
  maxTokens: 500,
});

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { text, toolResults } = await generateText({
  model: openai("gpt-4o"),
  tools: {
    lookup_price: tool({
      description: "Look up the price of a stock symbol.",
      parameters: z.object({ symbol: z.string() }),
      execute: async ({ symbol }) => ({ symbol, price: 185.5 }),
    }),
  },
  maxSteps: 5,   // allow multiple tool calls in one generateText call
  prompt: "What is the current price of AAPL?",
});

console.log(text);         // "The current price of AAPL is $185.50."
console.log(toolResults);  // [{ toolName: "lookup_price", result: { symbol: "AAPL", price: 185.5 } }]

import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

const result = streamText({
  model: openai("gpt-4o"),
  prompt: "Write a haiku about the ocean.",
});

// Option 1: iterate the text stream
for await (const chunk of result.textStream) {
  process.stdout.write(chunk);
}

// Option 2: await the full text after streaming ends
const fullText = await result.text;

// Option 3: read usage stats (only available after stream completes)
const { promptTokens, completionTokens } = await result.usage;

import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

const result = streamText({
  model: openai("gpt-4o"),
  prompt: "Explain quantum entanglement.",
});

// fullStream emits typed events: text-delta, tool-call, tool-result, finish, error
for await (const event of result.fullStream) {
  switch (event.type) {
    case "text-delta":
      process.stdout.write(event.textDelta);
      break;
    case "finish":
      console.log("\nFinish reason:", event.finishReason);
      console.log("Usage:", event.usage);
      break;
    case "error":
      console.error("Stream error:", event.error);
      break;
  }
}

// app/api/chat/route.ts
import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

export const runtime = "edge";

export async function POST(req: Request) {
  const { messages } = await req.json();

  const result = streamText({
    model: openai("gpt-4o"),
    messages,
    system: "You are a helpful assistant.",
  });

  // toDataStreamResponse() serialises the stream in the AI SDK wire format
  // that useChat() and useCompletion() in ai/react expect
  return result.toDataStreamResponse();
}

import { streamText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const result = streamText({
  model: openai("gpt-4o"),
  tools: {
    search: tool({
      description: "Search the web.",
      parameters: z.object({ query: z.string() }),
      execute: async ({ query }) => [{ title: "Result", url: "https://example.com" }],
    }),
  },
  prompt: "Search for the latest news about the James Webb telescope.",
});

// Tool call events arrive mid-stream
for await (const event of result.fullStream) {
  if (event.type === "tool-call")   console.log("Calling:", event.toolName, event.args);
  if (event.type === "tool-result") console.log("Got result:", event.result);
  if (event.type === "text-delta")  process.stdout.write(event.textDelta);
}

import { generateText, tool } from "ai";
import { openai } from "@ai-sdk/openai";
import { z } from "zod";

const { text, steps } = await generateText({
  model: openai("gpt-4o"),
  maxSteps: 10,   // allow up to 10 model calls in the loop
  tools: {
    get_weather: tool({
      description: "Get current weather for a city.",
      parameters: z.object({ city: z.string() }),
      execute: async ({ city }) => ({ city, temperature: 18, condition: "Cloudy" }),
    }),
    plan_route: tool({
      description: "Plan a driving route between two cities.",
      parameters: z.object({ from: z.string(), to: z.string() }),
      execute: async ({ from, to }) => ({ distance: "320km", duration: "3h 15m" }),
    }),
  },
  prompt: "Plan a road trip from Paris to Amsterdam, considering the weather at the destination.",
});

// steps records every model call and tool execution in the loop
for (const step of steps) {
  console.log(`Step ${step.stepType}: ${step.text.slice(0, 80)}`);
}

import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

const result = streamText({
  model: openai("gpt-4o"),
  prompt: "Describe how a neural network learns.",
  onChunk({ chunk }) {
    if (chunk.type === "text-delta") {
      // Called synchronously for each chunk — useful for logging or
      // writing to a database without changing the async iterator logic
      chunkBuffer.push(chunk.textDelta);
    }
  },
  onFinish({ text, usage, finishReason }) {
    // Called once the stream completes — log or persist the full response
    console.log("Tokens used:", usage.totalTokens, "Reason:", finishReason);
    saveToDatabase(text);
  },
});

// Continue consuming the stream normally
for await (const chunk of result.textStream) {
  process.stdout.write(chunk);
}

import { generateText } from "ai";
import { openai } from "@ai-sdk/openai";
import { APICallError } from "ai";

try {
  const { text } = await generateText({
    model: openai("gpt-4o"),
    prompt: "Hello",
    maxRetries: 3,
  });
} catch (err) {
  if (APICallError.isInstance(err)) {
    console.error("Provider error:", err.statusCode, err.message);
    console.error("Request URL:", err.url);
    console.error("Response body:", err.responseBody);
  } else {
    throw err;   // re-throw unexpected errors
  }
}

import { streamText } from "ai";
import { openai } from "@ai-sdk/openai";

const result = streamText({
  model: openai("gpt-4o"),
  prompt: "Tell me a story.",
});

try {
  for await (const chunk of result.textStream) {
    process.stdout.write(chunk);
  }
} catch (err) {
  // Errors mid-stream surface here
  console.error("Stream interrupted:", err);
}

// Alternatively, handle via fullStream events:
for await (const event of result.fullStream) {
  if (event.type === "error") {
    console.error("Stream event error:", event.error);
  }
}

